-- ============================================================================
-- Migración Completa: TransporteZC MySQL → Supabase (PostgreSQL)
-- Incluye todos los datos de clientes y usuarios embebidos
-- ============================================================================

-- Requiere: superuser en Supabase (para insertar en auth.users)
CREATE EXTENSION IF NOT EXISTS "pgcrypto";

-- ============================================================================
-- 1. ESQUEMA DESTINO
-- ============================================================================

-- Clientes
CREATE TABLE IF NOT EXISTS public.clients (
    id BIGINT PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    phone VARCHAR(255) NOT NULL,
    "documentID" VARCHAR(255) NOT NULL,
    email VARCHAR(255) NOT NULL,
    "creditLimit" VARCHAR(255) NOT NULL,
    status VARCHAR(255) NOT NULL,
    "createAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "createBy" VARCHAR(255) NOT NULL,
    carrer VARCHAR(255),
    balance NUMERIC(10,2) NOT NULL,
    uid UUID NOT NULL UNIQUE
);

-- Perfiles (vinculados a auth.users)
CREATE TABLE IF NOT EXISTS public.profiles (
    id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    type INTEGER NOT NULL CHECK (type IN (1, 2, 3)),
    display_name TEXT,
    phone VARCHAR(255),
    address VARCHAR(255),
    status VARCHAR(255) DEFAULT '0',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================================================
-- 2. TABLAS STAGING (reflectan estructura MySQL)
-- ============================================================================

CREATE SCHEMA IF NOT EXISTS staging;

DROP TABLE IF EXISTS staging.clients CASCADE;
CREATE TABLE staging.clients (
    id BIGINT PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    phone VARCHAR(255) NOT NULL,
    "documentID" VARCHAR(255) NOT NULL,
    email VARCHAR(255) NOT NULL,
    "creditLimit" VARCHAR(255) NOT NULL,
    status VARCHAR(255) NOT NULL,
    "createAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "createBy" VARCHAR(255) NOT NULL,
    carrer VARCHAR(255),
    balance NUMERIC(10,2) NOT NULL,
    uid UUID NOT NULL
);

DROP TABLE IF EXISTS staging.users CASCADE;
CREATE TABLE staging.users (
    id BIGINT PRIMARY KEY,
    username VARCHAR(255) NOT NULL,
    password VARCHAR(255) NOT NULL,
    type VARCHAR(11) NOT NULL,
    email VARCHAR(255) NOT NULL,
    confirm INTEGER NOT NULL DEFAULT 0,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    name VARCHAR(255) NOT NULL,
    phone VARCHAR(255) NOT NULL,
    address VARCHAR(255) NOT NULL,
    status VARCHAR(255) NOT NULL,
    idclient INTEGER
);

-- ============================================================================
-- 3. DATOS: CLIENTES (573 registros)
-- ============================================================================


-- ============================================================================
-- 4. DATOS: USUARIOS (587 registros)
-- ============================================================================


-- ============================================================================
-- 5. MIGRACIÓN: staging → destino
-- ============================================================================

DO $$
DECLARE
    rec RECORD;
    v_email TEXT;
    v_uid UUID;
    v_password TEXT;
    v_type INTEGER;
    v_created_at TIMESTAMPTZ;
    v_updated_at TIMESTAMPTZ;
    v_phone TEXT;
    v_address TEXT;
    v_status TEXT;
    v_name TEXT;
    v_username TEXT;
    v_idclient INT;
    skipped_count INT := 0;
    migrated_count INT := 0;
BEGIN
    RAISE NOTICE 'Iniciando migración de clientes...';

    -- Migrar clientes a public.clients
    SELECT id, name, phone, "documentID", email, "creditLimit", status, "createAt", "createBy", carrer, balance, uid
    FROM staging.clients
    ON CONFLICT (id) DO NOTHING;

    RAISE NOTICE 'Clientes migrados exitosamente.';

    RAISE NOTICE 'Iniciando migración de usuarios a auth.users + profiles...';

    -- Migrar usuarios
    FOR rec IN
        SELECT
            u.id,
            u.username,
            u.password,
            u.type,
            u.email,
            u.name,
            u.phone,
            u.address,
            u.status,
            u.idclient,
            u.created_at,
            u.updated_at,
            c.uid AS client_uid,
            c.email AS client_email
        FROM staging.users u
        LEFT JOIN staging.clients c ON c.id = u.idclient
        ORDER BY u.id
    LOOP
        -- Email: usar users.email si no está vacío, sino clients.email
        v_email := COALESCE(NULLIF(TRIM(rec.email), ''), NULLIF(TRIM(rec.client_email), ''));

        -- Saltar si no hay email
        IF v_email IS NULL OR v_email = '' THEN
            skipped_count := skipped_count + 1;
            CONTINUE;
        END IF;

        -- UUID: usar clients.uid si existe, sino generar uno
        IF rec.client_uid IS NOT NULL THEN
            v_uid := rec.client_uid;
        ELSE
            v_uid := gen_random_uuid();
        END IF;

        -- Contraseña: $2y$ → $2a$ (compatible con Supabase/Go)
        v_password := regexp_replace(rec.password, '^\$2y\$', '$2a$');

        -- Tipo: convertir VARCHAR → INTEGER
        v_type := rec.type::INTEGER;

        -- Timestamps
        v_created_at := COALESCE(rec.created_at, NOW());
        v_updated_at := COALESCE(rec.updated_at, NOW());

        -- Insertar en auth.users
        BEGIN
                instance_id,
                id,
                aud,
                role,
                email,
                encrypted_password,
                email_confirmed_at,
                confirmation_token,
                confirmation_sent_at,
                raw_app_meta_data,
                raw_user_meta_data,
                created_at,
                updated_at,
                is_super_admin,
                phone
            ) VALUES (
                '00000000-0000-0000-0000-000000000000'::uuid,
                v_uid,
                'authenticated',
                CASE WHEN v_type = 1 THEN 'admin' ELSE 'authenticated' END,
                v_email,
                v_password,
                NOW(),
                '',
                NULL,
                jsonb_build_object('provider', 'email', 'providers', jsonb_build_array('email')),
                jsonb_build_object('user_name', rec.name),
                v_created_at,
                v_updated_at,
                CASE WHEN v_type = 1 THEN true ELSE false END,
                rec.phone
            )
            ON CONFLICT (id) DO UPDATE SET
                email = EXCLUDED.email,
                encrypted_password = EXCLUDED.encrypted_password,
                raw_user_meta_data = EXCLUDED.raw_user_meta_data,
                updated_at = NOW();

            -- Insertar en public.profiles
            VALUES (
                v_uid,
                v_type,
                rec.name,
                rec.phone,
                rec.address,
                rec.status,
                v_created_at,
                v_updated_at
            )
            ON CONFLICT (id) DO UPDATE SET
                type = EXCLUDED.type,
                display_name = EXCLUDED.display_name,
                phone = EXCLUDED.phone,
                updated_at = NOW();

            migrated_count := migrated_count + 1;
        EXCEPTION WHEN OTHERS THEN
            RAISE WARNING 'Error migrando usuario ID=% email=%: %', rec.id, v_email, SQLERRM;
            skipped_count := skipped_count + 1;
        END;
    END LOOP;

    RAISE NOTICE 'Migración completada: % usuarios migrados, % omitidos', migrated_count, skipped_count;
END;
$$;

-- ============================================================================
-- 6. ÍNDICES
-- ============================================================================
CREATE INDEX IF NOT EXISTS idx_clients_uid ON public.clients(uid);
CREATE INDEX IF NOT EXISTS idx_clients_email ON public.clients(email);
CREATE INDEX IF NOT EXISTS idx_profiles_type ON public.profiles(type);

-- ============================================================================
-- 7. VERIFICACIÓN
-- ============================================================================
-- Ejecutar después de la migración:
-- SELECT 'clientes' AS tabla, COUNT(*) FROM public.clients
-- UNION ALL SELECT 'usuarios auth', COUNT(*) FROM auth.users
-- UNION ALL SELECT 'profiles', COUNT(*) FROM public.profiles
-- UNION ALL SELECT 'admins', COUNT(*) FROM public.profiles WHERE type = 1
-- UNION ALL SELECT 'estudiantes', COUNT(*) FROM public.profiles WHERE type = 2
-- UNION ALL SELECT 'conductores', COUNT(*) FROM public.profiles WHERE type = 3;
/*

Estructura del script:
Sección	Contenido
1. Esquema destino	public.clients + public.profiles
2. Tablas staging	staging.clients + staging.users (reflejan MySQL)
3. Datos clientes	573 clientes embebidos en INSERT INTO staging.clients
4. Datos usuarios	587 usuarios embebidos en INSERT INTO staging.users
5. Migración DO block	staging.clients → public.clients, staging.users → auth.users + public.profiles
6. Índices	idx_clients_uid, idx_clients_email, idx_profiles_type
Lógica de migración de usuarios:
- users.email vacío → fallback a clients.email via idclient
- UUIDs desde clients.uid, o gen_random_uuid() si no hay cliente asociado
- Contraseñas $2y$ → $2a$ (compatible Supabase/Go)
- raw_user_meta_data = {"user_name": <name>}
- raw_app_meta_data = {"provider": "email", "providers": ["email"]}
- Conductores (type=3) sin email se omiten con advertencia
Para ejecutar: sube el script al SQL Editor de Supabase (requiere superuser para insertar en auth.users).
*/